import { List, ActionPanel, Action, Icon, showToast, Toast, Color, Image } from "@raycast/api";
import { execSync } from "child_process";
import fs from "fs";
import path from "path";
import { useState, useMemo } from "react";

const SLICKER_DIR = path.join(process.env.HOME || "", ".config", "slicker");
const THEMES_DIR = path.join(SLICKER_DIR, "themes");
const USER_THEMES_DIR = path.join(SLICKER_DIR, "user", "themes");
const CURRENT_FILE = path.join(SLICKER_DIR, "theme", ".current");
const SLICKER_BIN = path.join(SLICKER_DIR, "bin", "slicker");

interface ThemeColors {
  accent: string;
  foreground: string;
  background: string;
  color1: string;
  color2: string;
  color4: string;
  color5: string;
  color6: string;
}

function parseColorsToml(filepath: string): ThemeColors | null {
  try {
    const content = fs.readFileSync(filepath, "utf-8");
    const colors: Record<string, string> = {};
    for (const line of content.split("\n")) {
      const match = line.match(/^(\w+)\s*=\s*"([^"]+)"/);
      if (match) {
        colors[match[1]] = match[2];
      }
    }
    return colors as unknown as ThemeColors;
  } catch {
    return null;
  }
}

function getCurrentTheme(): string {
  try {
    return fs.readFileSync(CURRENT_FILE, "utf-8").trim();
  } catch {
    return "";
  }
}

function getThemes(): { name: string; colors: ThemeColors | null; isUser: boolean }[] {
  const themes: { name: string; colors: ThemeColors | null; isUser: boolean }[] = [];
  const seen = new Set<string>();

  // User themes first (higher priority)
  if (fs.existsSync(USER_THEMES_DIR)) {
    for (const entry of fs.readdirSync(USER_THEMES_DIR, { withFileTypes: true })) {
      if (!entry.isDirectory() || entry.name === "templates") continue;
      const colorsFile = path.join(USER_THEMES_DIR, entry.name, "colors.toml");
      themes.push({ name: entry.name, colors: parseColorsToml(colorsFile), isUser: true });
      seen.add(entry.name);
    }
  }

  // Base themes
  if (fs.existsSync(THEMES_DIR)) {
    for (const entry of fs.readdirSync(THEMES_DIR, { withFileTypes: true })) {
      if (!entry.isDirectory() || entry.name === "templates" || seen.has(entry.name)) continue;
      const colorsFile = path.join(THEMES_DIR, entry.name, "colors.toml");
      themes.push({ name: entry.name, colors: parseColorsToml(colorsFile), isUser: false });
    }
  }

  return themes.sort((a, b) => a.name.localeCompare(b.name));
}

function colorCircle(hex: string): Image.ImageLike {
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16"><circle cx="8" cy="8" r="8" fill="${hex}"/></svg>`;
  return { source: `data:image/svg+xml;base64,${Buffer.from(svg).toString("base64")}` };
}

export default function Command() {
  const [current, setCurrent] = useState(getCurrentTheme);
  const themes = useMemo(getThemes, []);

  async function switchTheme(name: string) {
    const toast = await showToast({ style: Toast.Style.Animated, title: "Switching theme...", message: name });
    try {
      execSync(`/bin/bash -l -c '"${SLICKER_BIN}" theme set "${name}"'`, {
        timeout: 15000,
      });
      setCurrent(name);
      toast.style = Toast.Style.Success;
      toast.title = "Theme set";
      toast.message = name;
    } catch (e) {
      toast.style = Toast.Style.Failure;
      toast.title = "Failed to set theme";
      toast.message = String(e);
    }
  }

  return (
    <List>
      {themes.map((theme) => {
        const isCurrent = theme.name === current;
        const colors = theme.colors;

        return (
          <List.Item
            key={theme.name}
            icon={colors ? colorCircle(colors.accent) : Icon.Circle}
            title={theme.name}
            subtitle={theme.isUser ? "user" : undefined}
            accessories={[
              ...(colors
                ? [
                    { icon: colorCircle(colors.background), tooltip: `bg ${colors.background}` },
                    { icon: colorCircle(colors.foreground), tooltip: `fg ${colors.foreground}` },
                    { icon: colorCircle(colors.color1), tooltip: colors.color1 },
                    { icon: colorCircle(colors.color2), tooltip: colors.color2 },
                    { icon: colorCircle(colors.color4), tooltip: colors.color4 },
                    { icon: colorCircle(colors.color5), tooltip: colors.color5 },
                    { icon: colorCircle(colors.color6), tooltip: colors.color6 },
                  ]
                : []),
              ...(isCurrent ? [{ icon: Icon.Checkmark, tooltip: "Current theme" }] : []),
            ]}
            actions={
              <ActionPanel>
                <Action
                  title={isCurrent ? "Current Theme" : "Switch Theme"}
                  icon={isCurrent ? Icon.Checkmark : Icon.Switch}
                  onAction={() => switchTheme(theme.name)}
                />
              </ActionPanel>
            }
          />
        );
      })}
    </List>
  );
}
